AND dtr.add_datetime BETWEEN #{startTime} AND #{endTime}
GROUP BY DATE_FORMAT(dtr.add_datetime, '%Y-%m') ORDER BY timeLabel

choose.otherwise:
SELECT DATE_FORMAT(dtr.add_datetime, '%Y') as timeLabel, COUNT(*) as value FROM discussion_topic_reply dtr INNER JOIN discussion_topic dt ON dtr.topic_id = dt.id WHERE dt.textbook_id = #{textbookId}
AND dtr.add_datetime BETWEEN #{startTime} AND #{endTime}
GROUP BY DATE_FORMAT(dtr.add_datetime, '%Y') ORDER BY timeLabel

